861	}
862	
863	/* Enhancement generating shimmer */
864	@keyframes enhance-shimmer {
865	    0% {
866	        transform: translateX(-100%);
867	    }
868	    100% {
869	        transform: translateX(100%);
870	    }
871	}
872	
873	.enhance-shimmer-overlay {
874	    position: absolute;
875	    inset: 0;
876	    z-index: 5;
877	    overflow: hidden;
878	    border-radius: inherit;
879	    pointer-events: none;
880	    animation: enhance-shimmer-fade-in 0.4s ease forwards;
881	}
882	
883	@keyframes enhance-shimmer-fade-in {
884	    from {
885	        opacity: 0;
886	    }
887	    to {
888	        opacity: 1;
889	    }
890	}
891	
892	.enhance-shimmer-overlay::before {
893	    content: "";
