895	    inset: 0;
896	    background: oklch(0.98 0.004 85 / 0.12);
897	    backdrop-filter: blur(1px);
898	}
899	
900	.enhance-shimmer-overlay::after {
901	    content: "";
902	    position: absolute;
903	    inset: -50% -50% -50% -50%;
904	    width: 50%;
905	    background: linear-gradient(
906	        90deg,
907	        transparent,
908	        oklch(0.68 0.07 28 / 0.1),
909	        oklch(0.68 0.07 28 / 0.18),
910	        oklch(0.68 0.07 28 / 0.1),
