914	}
915	
916	.dark .enhance-shimmer-overlay::before {
917	    background: oklch(0.09 0 0 / 0.18);
918	}
919	
920	.dark .enhance-shimmer-overlay::after {
921	    background: linear-gradient(
922	        90deg,
923	        transparent,
924	        oklch(0.75 0.05 25 / 0.08),
