926	        oklch(0.75 0.05 25 / 0.08),
927	        transparent
928	    );
929	}
930	
931	/* Dot grid background */
932	.dot-grid {
933	    background-image: radial-gradient(
934	        circle,
935	        oklch(0.45 0 0 / 0.08) 1px,
936	        transparent 1px
937	    );
938	    background-size: 32px 32px;
939	}
940	
941	.dark .dot-grid {
942	    background-image: radial-gradient(
943	        circle,
944	        oklch(1 0 0 / 0.08) 1px,
945	        transparent 1px
946	    );
947	}
948	
949	/* Glass nav */
950	.glass-nav {
951	    backdrop-filter: blur(12px) saturate(1.5);
952	    background: oklch(0.98 0 0 / 0.8);
953	    border-bottom: 1px solid oklch(0 0 0 / 0.06);
954	}
955	
956	.dark .glass-nav {
957	    background: oklch(0.09 0 0 / 0.8);
958	    border-bottom: 1px solid oklch(1 0 0 / 0.06);
959	}
960	
961	/* Transcript bubble recording ring */
962	@keyframes recording-ring-pulse {
963	    0% {
964	        transform: scale(1);
965	        opacity: 0.4;
966	    }
967	
968	    100% {
969	        transform: scale(1.5);
970	        opacity: 0;
971	    }
972	}
973	
974	/* Recording waveform animation */
975	@keyframes pulse {
976	    0% {
977	        transform: scaleY(0.4);
978	    }
979	
980	    100% {
981	        transform: scaleY(1);
982	    }
983	}
984	
985	/* Chat bar ambient glow pulse */
986	@keyframes chat-glow-pulse {
987	    0%,
988	    100% {
