990	            0 0 15px 0 oklch(0.65 0.08 25 / 0.15),
991	            0 4px 24px -4px oklch(0 0 0 / 0.12);
992	    }
993	
994	    50% {
995	        box-shadow:
996	            0 0 30px 4px oklch(0.65 0.08 25 / 0.3),
997	            0 4px 24px -4px oklch(0 0 0 / 0.12);
998	    }
999	}
1000	
1001	.chat-glow-pulse {
1002	    animation: chat-glow-pulse 2s ease-in-out infinite;
1003	}
1004	
1005	/* Respect user motion preferences (Vercel guideline: Honor prefers-reduced-motion) */
1006	@media (prefers-reduced-motion: reduce) {
1007	    *,
1008	    *::before,
1009	    *::after {
1010	        animation-duration: 0.01ms !important;
1011	        animation-iteration-count: 1 !important;
1012	        transition-duration: 0.01ms !important;
1013	        scroll-behavior: auto !important;
1014	    }
1015	}
