@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

/* noter: monochrome theme with warm rose accent */
:root {
    --background: oklch(0.985 0.004 85);
    --foreground: oklch(0.18 0.01 80);
    --card: oklch(1 0 0);
    --card-foreground: oklch(0.18 0.01 80);
    --popover: oklch(1 0 0);
    --popover-foreground: oklch(0.18 0.01 80);
    --primary: oklch(0.18 0.01 80);
    --primary-foreground: oklch(0.98 0 0);
    --secondary: oklch(0.958 0.004 85);
    --secondary-foreground: oklch(0.2 0.01 80);
    --muted: oklch(0.95 0.004 85);
    --muted-foreground: oklch(0.49 0.01 80);
    --accent: oklch(0.68 0.07 28);
    --accent-foreground: oklch(0.98 0 0);
    --destructive: oklch(0.55 0.22 27);
    --destructive-foreground: oklch(0.98 0 0);
    --border: oklch(0.9 0.004 85);
    --input: oklch(0.9 0.004 85);
    --ring: oklch(0.68 0.07 28);
    --chart-1: oklch(0.68 0.07 28);
    --chart-2: oklch(0.55 0 0);
    --chart-3: oklch(0.45 0 0);
    --chart-4: oklch(0.7 0.04 60);
    --chart-5: oklch(0.6 0.05 200);
    --radius: 0.75rem;
    --sidebar: oklch(0.972 0.004 85);
    --sidebar-foreground: oklch(0.18 0.01 80);
    --sidebar-primary: oklch(0.18 0.01 80);
    --sidebar-primary-foreground: oklch(0.98 0 0);
    --sidebar-accent: oklch(0.94 0.004 85);
    --sidebar-accent-foreground: oklch(0.18 0.01 80);
    --sidebar-border: oklch(0.9 0.004 85);
    --sidebar-ring: oklch(0.68 0.07 28);
    --assistant-glass: oklch(1 0 0 / 0.72);
    --assistant-glass-strong: oklch(1 0 0 / 0.82);
    --assistant-glass-soft: oklch(0.97 0.004 85 / 0.58);
    --assistant-glass-border: oklch(0.84 0.01 85 / 0.6);
    --assistant-glass-shadow: 0 32px 70px -40px oklch(0.18 0.01 80 / 0.32);
    --assistant-glass-inset: inset 0 1px 0 oklch(1 0 0 / 0.72);
    --recording: oklch(0.66 0.11 24);
    --recording-soft: oklch(0.74 0.07 24 / 0.42);
    --enhance-insert-border: oklch(0.62 0.17 155);
    --enhance-insert-bg: oklch(0.62 0.17 155 / 0.06);
    --enhance-delete-border: oklch(0.62 0.2 18);
    --enhance-delete-bg: oklch(0.62 0.2 18 / 0.06);
    --enhance-replace-border: oklch(0.7 0.14 75);
    --enhance-replace-bg: oklch(0.7 0.14 75 / 0.06);
    --enhance-accepted-bg: oklch(0.62 0.17 155 / 0.05);
    --enhance-rejected-bg: oklch(0 0 0 / 0.02);
}

.dark {
    --background: oklch(0.09 0 0);
    --foreground: oklch(0.95 0 0);
    --card: oklch(0.11 0 0);
    --card-foreground: oklch(0.95 0 0);
    --popover: oklch(0.11 0 0);
    --popover-foreground: oklch(0.95 0 0);
