    --accent-foreground: oklch(0.09 0 0);
    --destructive: oklch(0.58 0.22 27);
    --destructive-foreground: oklch(0.95 0 0);
    --border: oklch(0.19 0 0);
    --input: oklch(0.19 0 0);
    --ring: oklch(0.75 0.05 25);
    --chart-1: oklch(0.75 0.05 25);
