    --sidebar-accent: oklch(0.17 0 0);
    --sidebar-accent-foreground: oklch(0.9 0 0);
    --sidebar-border: oklch(0.19 0 0);
    --sidebar-ring: oklch(0.75 0.05 25);
    --assistant-glass: oklch(0.18 0.004 85 / 0.72);
    --assistant-glass-strong: oklch(0.22 0.004 85 / 0.8);
    --assistant-glass-soft: oklch(0.16 0.004 85 / 0.62);
    --assistant-glass-border: oklch(0.42 0.01 85 / 0.42);
    --assistant-glass-shadow: 0 36px 80px -44px oklch(0 0 0 / 0.55);
    --assistant-glass-inset: inset 0 1px 0 oklch(1 0 0 / 0.08);
    --recording: oklch(0.73 0.08 24);
    --recording-soft: oklch(0.73 0.08 24 / 0.34);
    --enhance-insert-border: oklch(0.72 0.15 155);
    --enhance-insert-bg: oklch(0.72 0.15 155 / 0.08);
    --enhance-delete-border: oklch(0.72 0.18 18);
    --enhance-delete-bg: oklch(0.72 0.18 18 / 0.08);
    --enhance-replace-border: oklch(0.78 0.12 75);
    --enhance-replace-bg: oklch(0.78 0.12 75 / 0.08);
