@theme inline {
    --font-sans:
        "SF Pro Text", "SF Pro Display", "Segoe UI", "Helvetica Neue", Arial,
        sans-serif;
    --font-mono:
        "SFMono-Regular", "SF Mono", Menlo, Monaco, Consolas, "Liberation Mono",
        monospace;
    --color-background: var(--background);
    --color-foreground: var(--foreground);
    --color-card: var(--card);
    --color-card-foreground: var(--card-foreground);
    --color-popover: var(--popover);
    --color-popover-foreground: var(--popover-foreground);
    --color-primary: var(--primary);
    --color-primary-foreground: var(--primary-foreground);
    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--secondary-foreground);
    --color-muted: var(--muted);
    --color-muted-foreground: var(--muted-foreground);
    --color-accent: var(--accent);
    --color-accent-foreground: var(--accent-foreground);
    --color-destructive: var(--destructive);
    --color-destructive-foreground: var(--destructive-foreground);
    --color-border: var(--border);
    --color-input: var(--input);
    --color-ring: var(--ring);
    --color-chart-1: var(--chart-1);
    --color-chart-2: var(--chart-2);
    --color-chart-3: var(--chart-3);
    --color-chart-4: var(--chart-4);
    --color-chart-5: var(--chart-5);
    --radius-sm: calc(var(--radius) - 4px);
    --radius-md: calc(var(--radius) - 2px);
    --radius-lg: var(--radius);
    --radius-xl: calc(var(--radius) + 4px);
    --color-sidebar: var(--sidebar);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar-primary: var(--sidebar-primary);
    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
    * {
        @apply border-border outline-ring/50;
    }

    body {
        @apply bg-background text-foreground;
    }
}

@layer utilities {
    .surface-document {
        @apply rounded-[28px] border border-border/70 bg-card shadow-[0_18px_40px_-32px_oklch(0.18_0.01_80/0.18)];
    }

    .surface-utility {
        background: linear-gradient(
            180deg,
            color-mix(
                in oklch,
                var(--assistant-glass-strong) 74%,
                var(--background)
            ),
            color-mix(in oklch, var(--assistant-glass) 66%, var(--background))
        );
        border: 1px solid
            color-mix(
                in oklch,
                var(--assistant-glass-border) 62%,
                var(--border)
            );
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.34),
            0 20px 42px -34px oklch(0.18 0.01 80 / 0.16);
        backdrop-filter: blur(20px) saturate(1.04);
    }

    .surface-status {
        @apply rounded-[24px] border;
    }

    .surface-empty {
        @apply rounded-[24px] border border-dashed border-border/70 bg-secondary/35;
    }

    /* Dark mode overrides for liquid-glass classes */
    .dark .liquid-glass-chip,
    .dark .liquid-glass-control,
    .dark .liquid-glass-button {
        background: linear-gradient(
            180deg,
            oklch(0.22 0 0 / 0.66),
            oklch(0.16 0 0 / 0.5)
        );
        border: 1px solid oklch(0.34 0 0 / 0.55);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.06),
            0 12px 24px -20px oklch(0 0 0 / 0.55);
    }

    .dark .liquid-glass-dock {
        background: linear-gradient(
            180deg,
            oklch(0.22 0.002 85 / 0.66),
            oklch(0.16 0 0 / 0.52)
        );
        border: 1px solid oklch(0.34 0.004 85 / 0.42);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.06),
            0 18px 40px -28px oklch(0 0 0 / 0.52);
    }

    .dark .liquid-glass-orb {
        background:
            radial-gradient(
                circle at 30% 20%,
                oklch(1 0 0 / 0.07),
                transparent 46%
            ),
            linear-gradient(
                160deg,
                oklch(0.24 0 0 / 0.64),
                oklch(0.18 0 0 / 0.5)
            );
        border: 1px solid oklch(0.34 0 0 / 0.52);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.07),
            0 18px 28px -24px oklch(0 0 0 / 0.55);
    }

    .dark .liquid-glass-toolbar {
        background: linear-gradient(
            180deg,
            oklch(0.24 0.003 85 / 0.56),
            oklch(0.18 0 0 / 0.42)
        );
        border: 1px solid oklch(0.34 0.004 85 / 0.38);
        box-shadow: inset 0 1px 0 oklch(1 0 0 / 0.05);
    }

    .dark .liquid-glass-popover {
        background: linear-gradient(
            180deg,
            oklch(0.24 0.003 85 / 0.82),
            oklch(0.16 0 0 / 0.7)
        );
        border: 1px solid oklch(0.34 0.004 85 / 0.4);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.06),
            0 22px 44px -30px oklch(0 0 0 / 0.55);
        backdrop-filter: blur(20px) saturate(1.08);
    }

    .dark .liquid-glass-context-chip {
        background: linear-gradient(
            180deg,
            oklch(0.28 0.01 85 / 0.74),
            oklch(0.19 0 0 / 0.58)
        );
        border: 1px solid oklch(0.4 0.01 85 / 0.42);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.08),
            0 12px 24px -24px oklch(0 0 0 / 0.52);
    }

    .dark .liquid-glass-input {
        background: linear-gradient(
            180deg,
            oklch(0.22 0.003 85 / 0.52),
            oklch(0.16 0 0 / 0.38)
        );
        border: 1px solid oklch(0.34 0.004 85 / 0.34);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.05),
            0 16px 34px -30px oklch(0 0 0 / 0.42);
    }

    /* Interactive glass — adds hover/active micro-reactions */
    .liquid-glass-interactive {
        transition:
            transform 0.12s ease,
            filter 0.12s ease,
            box-shadow 0.15s ease;
    }

    .liquid-glass-interactive:hover {
        transform: translateY(-1px);
        filter: brightness(1.04);
    }

    .liquid-glass-interactive:active {
        transform: scale(0.96);
        filter: brightness(0.97);
        transition-duration: 0.06s;
    }

    .liquid-glass-fab {
        background:
            radial-gradient(
                circle at 30% 18%,
                oklch(1 0 0 / 0.74),
                transparent 44%
            ),
            linear-gradient(
                160deg,
                oklch(1 0 0 / 0.56),
                oklch(0.93 0.004 85 / 0.42)
            );
        border: 1px solid oklch(1 0 0 / 0.52);
        color: var(--foreground);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.86),
            0 20px 40px -22px oklch(0.18 0.01 80 / 0.3);
        backdrop-filter: blur(20px) saturate(1.15);
        transition:
            filter 0.12s ease,
            transform 0.1s ease,
            box-shadow 0.15s ease;
    }

    .liquid-glass-fab:hover {
        filter: brightness(1.06);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.9),
            0 24px 48px -22px oklch(0.18 0.01 80 / 0.4);
    }

    .liquid-glass-fab:active {
        transform: scale(0.96);
        transition-duration: 0.06s;
    }

    .dark .liquid-glass-fab {
        background:
            radial-gradient(
                circle at 30% 18%,
                oklch(1 0 0 / 0.07),
                transparent 44%
            ),
            linear-gradient(
                160deg,
                oklch(0.26 0 0 / 0.7),
                oklch(0.18 0 0 / 0.52)
