        border: 1px solid oklch(0.38 0 0 / 0.58);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.09),
            0 20px 40px -22px oklch(0 0 0 / 0.65);
    }

    .liquid-glass-shell {
        background: linear-gradient(
            180deg,
            var(--assistant-glass-strong),
            var(--assistant-glass) 44%,
            var(--assistant-glass-soft)
