        border: 1px solid
            color-mix(in oklch, var(--assistant-glass-border) 78%, white);
        box-shadow: var(--assistant-glass-inset), var(--assistant-glass-shadow);
        backdrop-filter: blur(28px) saturate(1.12);
    }

    .liquid-glass-shell[data-generating="true"] {
        border-color: color-mix(
            in oklch,
            var(--ring) 48%,
            var(--assistant-glass-border)
        );
        box-shadow:
            var(--assistant-glass-inset),
            0 0 0 1px color-mix(in oklch, var(--ring) 18%, transparent),
            0 0 0 6px color-mix(in oklch, var(--ring) 10%, transparent),
            0 26px 58px -32px color-mix(in oklch, var(--ring) 34%, transparent);
    }

    .liquid-glass-dock {
        background: linear-gradient(
            180deg,
            oklch(1 0 0 / 0.46),
            oklch(0.98 0.003 85 / 0.28)
        );
        border: 1px solid oklch(1 0 0 / 0.34);
        box-shadow:
            inset 0 1px 0 oklch(1 0 0 / 0.72),
