    .liquid-glass-orb {
        background:
            radial-gradient(
                circle at 30% 20%,
                oklch(1 0 0 / 0.86),
                transparent 46%
            ),
            linear-gradient(
                160deg,
                oklch(1 0 0 / 0.62),
