/* Surface thinking — pulsing accent-glow border during AI generation */
@keyframes surface-thinking-glow {
    0%,
    100% {
        box-shadow: 0 16px 40px -30px oklch(0.18 0.01 80 / 0.26);
    }
    50% {
        box-shadow:
            0 0 0 1.5px oklch(0.68 0.07 28 / 0.22),
            0 20px 48px -26px oklch(0.18 0.01 80 / 0.32),
            0 0 24px oklch(0.68 0.07 28 / 0.06);
    }
}

@keyframes surface-thinking-glow-dark {
    0%,
    100% {
        box-shadow: 0 16px 40px -30px oklch(0 0 0 / 0.5);
    }
    50% {
        box-shadow:
            0 0 0 1.5px oklch(0.75 0.05 25 / 0.25),
            0 20px 48px -26px oklch(0 0 0 / 0.6),
            0 0 24px oklch(0.75 0.05 25 / 0.08);
    }
}

.surface-thinking {
    animation: surface-thinking-glow 2s ease-in-out infinite;
}

.dark .surface-thinking {
    animation: surface-thinking-glow-dark 2s ease-in-out infinite;
}

/* Tiptap / ProseMirror editor styles */
.prose-editor {
    min-height: 360px;
    padding-top: 0.25rem;
    line-height: 1.8;
    color: var(--foreground);
    max-width: none;
}

.prose-editor p {
    margin-bottom: 0.8rem;
    font-size: 0.95rem;
}
.prose-editor p.is-editor-empty:first-child::before {
    content: attr(data-placeholder);
    float: left;
    color: var(--muted-foreground);
    pointer-events: none;
    height: 0;
    font-size: 0.95rem;
}

.prose-editor h1 {
    font-size: 1.5rem;
    font-weight: 600;
    margin: 1.5rem 0 0.75rem;
    letter-spacing: -0.02em;
}
.prose-editor h2 {
    font-size: 1.1rem;
    font-weight: 600;
    margin: 1.25rem 0 0.5rem;
    letter-spacing: -0.015em;
}
.prose-editor h3 {
    font-size: 0.98rem;
    font-weight: 600;
    margin: 1rem 0 0.35rem;
}

.prose-editor ul {
    list-style: disc;
    padding-left: 1.25rem;
    margin-bottom: 0.9rem;
}
.prose-editor ol {
    list-style: decimal;
    padding-left: 1.25rem;
    margin-bottom: 0.9rem;
}
.prose-editor li {
    margin-bottom: 0.35rem;
    font-size: 0.95rem;
}

.prose-editor ul[data-type="taskList"] {
    list-style: none;
    padding-left: 0;
}
.prose-editor ul[data-type="taskList"] li {
    display: flex;
    align-items: flex-start;
    gap: 0.5rem;
    margin-bottom: 0.375rem;
}
.prose-editor ul[data-type="taskList"] li > label {
    display: flex;
    align-items: center;
    margin-top: 0.125rem;
    cursor: pointer;
    flex-shrink: 0;
}
.prose-editor ul[data-type="taskList"] li > label input[type="checkbox"] {
    width: 0.875rem;
    height: 0.875rem;
    accent-color: var(--accent);
    cursor: pointer;
}
.prose-editor ul[data-type="taskList"] li > div {
    flex: 1;
    min-width: 0;
}
.prose-editor ul[data-type="taskList"] li[data-checked="true"] > div {
    color: var(--muted-foreground);
    text-decoration: line-through;
}

.prose-editor blockquote {
    border-left: 2px solid var(--border);
    padding-left: 1rem;
    color: var(--muted-foreground);
    margin: 0.75rem 0;
    font-style: italic;
}

.prose-editor strong {
    font-weight: 600;
}
.prose-editor em {
    font-style: italic;
}
.prose-editor code {
    font-family: var(--font-mono);
    font-size: 0.8125rem;
    background: var(--secondary);
    padding: 0.1em 0.3em;
    border-radius: 3px;
}

/* Landing and auth reveal */
@keyframes reveal-up {
    from {
        opacity: 0;
        transform: translateY(18px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.landing-stagger,
.landing-fade,
.auth-enter {
    opacity: 0;
    animation: reveal-up 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

.landing-badge {
    background: linear-gradient(
        180deg,
        oklch(1 0 0 / 0.9),
        oklch(0.97 0.004 85 / 0.7)
    );
    box-shadow: inset 0 1px 0 oklch(1 0 0 / 0.75);
}

/* Scroll-triggered reveal */
.reveal-up {
    opacity: 0;
    transform: translateY(24px);
}

.reveal-up.revealed {
    animation: reveal-up 0.7s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

/* Base shimmer animation for buttons/CTAs */
@keyframes shimmer {
    0% {
        transform: translateX(-100%);
    }
    100% {
        transform: translateX(100%);
    }
}

/* Glass chip entrance — floats in from above with a blur dissolve */
@keyframes glass-chip-in {
    from {
        opacity: 0;
        transform: translateY(-8px) scale(0.9);
        filter: blur(3px);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
        filter: blur(0);
    }
}

.glass-chip-enter {
    animation: glass-chip-in 0.32s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

/* Enhancement review card entrance */
@keyframes enhance-card-in {
    from {
        opacity: 0;
        transform: translateY(16px) scale(0.98);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

.enhance-card-in {
    opacity: 0;
    animation: enhance-card-in 0.45s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

/* Enhancement generating shimmer */
@keyframes enhance-shimmer {
    0% {
        transform: translateX(-100%);
    }
    100% {
        transform: translateX(100%);
    }
}

.enhance-shimmer-overlay {
    position: absolute;
    inset: 0;
    z-index: 5;
    overflow: hidden;
    border-radius: inherit;
    pointer-events: none;
    animation: enhance-shimmer-fade-in 0.4s ease forwards;
}

@keyframes enhance-shimmer-fade-in {
    from {
        opacity: 0;
    }
    to {
        opacity: 1;
    }
}

.enhance-shimmer-overlay::before {
    content: "";
    position: absolute;
    inset: 0;
    background: oklch(0.98 0.004 85 / 0.12);
    backdrop-filter: blur(1px);
}

.enhance-shimmer-overlay::after {
    content: "";
    position: absolute;
    inset: -50% -50% -50% -50%;
    width: 50%;
    background: linear-gradient(
        90deg,
        transparent,
        oklch(0.68 0.07 28 / 0.1),
        oklch(0.68 0.07 28 / 0.18),
        oklch(0.68 0.07 28 / 0.1),
        transparent
    );
    animation: enhance-shimmer 2s ease-in-out infinite;
}

.dark .enhance-shimmer-overlay::before {
    background: oklch(0.09 0 0 / 0.18);
}

.dark .enhance-shimmer-overlay::after {
    background: linear-gradient(
        90deg,
        transparent,
        oklch(0.75 0.05 25 / 0.08),
        oklch(0.75 0.05 25 / 0.14),
        oklch(0.75 0.05 25 / 0.08),
        transparent
    );
}

/* Dot grid background */
.dot-grid {
    background-image: radial-gradient(
        circle,
        oklch(0.45 0 0 / 0.08) 1px,
        transparent 1px
    );
    background-size: 32px 32px;
}

.dark .dot-grid {
    background-image: radial-gradient(
        circle,
        oklch(1 0 0 / 0.08) 1px,
        transparent 1px
    );
}

/* Glass nav */
.glass-nav {
    backdrop-filter: blur(12px) saturate(1.5);
    background: oklch(0.98 0 0 / 0.8);
    border-bottom: 1px solid oklch(0 0 0 / 0.06);
}

.dark .glass-nav {
    background: oklch(0.09 0 0 / 0.8);
    border-bottom: 1px solid oklch(1 0 0 / 0.06);
}

/* Transcript bubble recording ring */
@keyframes recording-ring-pulse {
    0% {
        transform: scale(1);
        opacity: 0.4;
    }

    100% {
        transform: scale(1.5);
        opacity: 0;
    }
}

/* Recording waveform animation */
@keyframes pulse {
    0% {
        transform: scaleY(0.4);
    }

    100% {
        transform: scaleY(1);
    }
}

/* Chat bar ambient glow pulse */
@keyframes chat-glow-pulse {
    0%,
    100% {
        box-shadow:
            0 0 15px 0 oklch(0.65 0.08 25 / 0.15),
            0 4px 24px -4px oklch(0 0 0 / 0.12);
    }

    50% {
        box-shadow:
            0 0 30px 4px oklch(0.65 0.08 25 / 0.3),
            0 4px 24px -4px oklch(0 0 0 / 0.12);
    }
}

.chat-glow-pulse {
    animation: chat-glow-pulse 2s ease-in-out infinite;
}

/* Respect user motion preferences (Vercel guideline: Honor prefers-reduced-motion) */
@media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
        scroll-behavior: auto !important;
    }
}

import * as React from 'react'
import { Slot } from '@radix-ui/react-slot'
import { cva, type VariantProps } from 'class-variance-authority'

import { cn } from '@/lib/utils'

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-lg text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: 'bg-primary text-primary-foreground hover:bg-primary/90',
        destructive:
          'bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60',
        outline:
          'border bg-background shadow-xs hover:bg-secondary hover:text-secondary-foreground dark:bg-input/30 dark:border-input',
        secondary:
          'bg-secondary text-secondary-foreground hover:bg-secondary/80',
        ghost:
          'hover:bg-secondary hover:text-secondary-foreground',
        'ghost-icon':
          'text-muted-foreground hover:bg-secondary hover:text-foreground',
        'ghost-destructive':
          'text-muted-foreground hover:bg-destructive/10 hover:text-destructive',
        link: 'text-primary underline-offset-4 hover:underline',
      },
      size: {
        default: 'h-9 px-4 py-2 has-[>svg]:px-3',
        sm: 'h-8 rounded-lg gap-1.5 px-3 has-[>svg]:px-2.5',
        lg: 'h-10 rounded-lg px-6 has-[>svg]:px-4',
        icon: 'size-9',
        'icon-xs': 'size-7',
        'icon-sm': 'size-8',
        'icon-lg': 'size-10',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  },
)

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: React.ComponentProps<'button'> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot : 'button'

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

