    name: template.name,
    description: template.description ?? '',
    prompt: template.prompt,
    isBuiltin: false,
  }
}

export function formatTemplateContext(template: ResolvedNoteTemplate) {
  return [
    `Selected note format: ${template.name}`,
    template.description ? `Description: ${template.description}` : null,
    'Format instructions:',
    template.prompt,
  ]
    .filter(Boolean)
    .join('\n')
}

import { z } from 'zod'
import * as Sentry from '@sentry/nextjs'
import { createRateLimiter, checkRateLimit } from '@/lib/api/rate-limit'
import { createClient } from '@/lib/supabase/server'
import { errorResponse } from '@/lib/api/api-helpers'
import { validateBody } from '@/lib/api/validate'
import { isTiptapDocument } from '@/lib/tiptap/tiptap-converter'
import { resolveMeetingTemplate } from '@/lib/note-template'
import type { EnhancementState, Meeting } from '@/lib/types'
import type { SupabaseClient } from '@supabase/supabase-js'

export { DraftProposalValidationError } from '@/lib/notes/draft-proposal'

const ratelimit = createRateLimiter(5, '1 m')

const tiptapDocumentSchema = z.unknown().refine(
  (v) => v == null || isTiptapDocument(v),
  { message: 'documentContent must be a valid Tiptap document or omitted' }
)

const requestSchema = z.discriminatedUnion('action', [
  z.object({
    action: z.literal('generate'),
    mode: z.enum(['generate', 'enhance']),
    documentContent: tiptapDocumentSchema,
  }),
  z.object({
    action: z.literal('complete'),
    outcome: z.enum(['accepted', 'dismissed']),
    sourceHash: z.string().trim().min(1),
    documentContent: tiptapDocumentSchema.optional(),
  }),
])

export type ParsedRequestBody = z.infer<typeof requestSchema>

export function normalizeEnhancementState(value: unknown): EnhancementState {
  const state = value && typeof value === 'object'
    ? (value as Record<string, unknown>)
    : {}

  return {
    lastReviewedSourceHash:
      typeof state.lastReviewedSourceHash === 'string' ? state.lastReviewedSourceHash : null,
    lastOutcome:
      state.lastOutcome === 'accepted' || state.lastOutcome === 'dismissed'
        ? state.lastOutcome
        : null,
    lastReviewedAt:
      typeof state.lastReviewedAt === 'string' ? state.lastReviewedAt : null,
    lastError:
      typeof state.lastError === 'string' ? state.lastError : null,
  }
}

export function getStructuredContext(
  meeting: Pick<
    Meeting,
    'summary' | 'detailed_notes' | 'action_items' | 'key_decisions' | 'topics' | 'follow_ups'
  >
) {
  return JSON.stringify(
    {
      summary: meeting.summary ?? '',
      detailed_notes: meeting.detailed_notes ?? '',
      action_items: meeting.action_items ?? [],
      key_decisions: meeting.key_decisions ?? [],
      topics: meeting.topics ?? [],
      follow_ups: meeting.follow_ups ?? [],
    },
    null,
    2
  )
}

export interface ValidatedEnhanceRequest {
  meeting: Meeting
  parsedBody: ParsedRequestBody
  supabase: SupabaseClient
  userId: string
  persistedState: EnhancementState
  template: Awaited<ReturnType<typeof resolveMeetingTemplate>>
}

export async function validateEnhanceRequest(
  request: Request,
  meetingId: string,
): Promise<ValidatedEnhanceRequest | Response> {
  const supabase = await createClient()

  const parsedBody = await validateBody(request, requestSchema)
  if (parsedBody instanceof Response) return parsedBody

  const {
    data: { user },
  } = await supabase.auth.getUser()
  if (!user) {
    return errorResponse('Unauthorized', 'UNAUTHORIZED', 401)
  }

  const allowed = await checkRateLimit(ratelimit, `enhance_${user.id}`, 'meetings/enhance')
  if (!allowed) {
    return errorResponse('Too Many Requests', 'RATE_LIMITED', 429)
  }

  const { data: meeting } = await supabase
    .from('meetings')
    .select('id, transcript, template_id, document_content, enhancement_state, summary, detailed_notes, action_items, key_decisions, topics, follow_ups')
    .eq('id', meetingId)
    .eq('user_id', user.id)
    .single()

  if (!meeting) {
    return errorResponse('Meeting not found', 'MEETING_NOT_FOUND', 404)
  }

  if (!meeting.transcript || !meeting.transcript.trim()) {
    return errorResponse(
      'Transcript is required before generating note drafts',
      'MISSING_TRANSCRIPT',
      400
    )
  }

  const persistedState = normalizeEnhancementState(meeting.enhancement_state)

  let template: Awaited<ReturnType<typeof resolveMeetingTemplate>>
  try {
    template = await resolveMeetingTemplate(
      supabase as { from: (table: string) => any },
      {
        template_id: meeting.template_id,
        user_id: user.id,
      }
    )
  } catch (error: unknown) {
    Sentry.captureException(error, { tags: { route: 'meetings/enhance', phase: 'template-resolve' } })
    return errorResponse('Failed to resolve meeting template', 'TEMPLATE_ERROR', 500)
  }

  return {
    meeting: meeting as Meeting,
    parsedBody: parsedBody.data,
    supabase: supabase as SupabaseClient,
    userId: user.id,
    persistedState,
    template,
  }
}

import { getOpenAI } from '@/lib/openai'
import { normalizeStringArray, normalizeActionItems } from '@/lib/notes/note-normalization'
import { buildNotesGenerationPrompt } from '@/lib/notes/prompts'
import { generatedNotesSchema } from '@/lib/schemas'
import { resolveMeetingTemplate, type ResolvedNoteTemplate } from '@/lib/note-template'
import { formatTranscriptForNotes, countSpeakers, buildMeetingContextHeader } from '@/lib/transcript-formatter'
import { METADATA_MODEL } from '@/lib/ai-models'
import { MAX_TRANSCRIPT_CHARS } from '@/lib/truncation-limits'
import type { DiarizedSegment } from '@/lib/types'

type SupabaseClient = {
  from: (table: string) => unknown
}

export interface GenerateNotesInput {
  transcript: string
  templateId: string | null
  userId: string
  diarizedTranscript?: DiarizedSegment[] | null
  audioDuration?: number | null
}

export interface GeneratedNotes {
  title: string
  summary: string
  detailed_notes: string
  action_items: ReturnType<typeof normalizeActionItems>
  key_decisions: string[]
  topics: string[]
  follow_ups: string[]
}

function shouldRetryWithoutStructuredResponseFormat(error: unknown) {
  if (!(error instanceof Error)) return false

  const message = error.message.toLowerCase()
  return (
    message.includes('invalid input') ||
    message.includes('response_format') ||
    message.includes('json_object')
  )
}

/**
 * Generates structured meeting notes from a transcript using AI.
 * Shared between the direct `/api/generate-notes` route and the background worker.
 */
export async function generateNotesFromTranscript(
  supabase: SupabaseClient,
  input: GenerateNotesInput,
): Promise<GeneratedNotes> {
  const { transcript, templateId, userId, diarizedTranscript, audioDuration } = input

  const truncatedTranscript = transcript.length > MAX_TRANSCRIPT_CHARS
    ? transcript.slice(0, MAX_TRANSCRIPT_CHARS) + '\n\n[Transcript truncated due to length]'
    : transcript

  const template: ResolvedNoteTemplate = await resolveMeetingTemplate(
    supabase as Parameters<typeof resolveMeetingTemplate>[0],
    { template_id: templateId, user_id: userId },
  )

  const formattedTranscript = formatTranscriptForNotes(truncatedTranscript, diarizedTranscript)

  const speakerCount = countSpeakers(diarizedTranscript)
  const contextHeader = buildMeetingContextHeader({
    templateName: template.name,
    audioDuration: audioDuration ?? null,
    speakerCount,
  })
  const messages = [
    { role: 'system' as const, content: buildNotesGenerationPrompt(template) },
    { role: 'user' as const, content: `${contextHeader}\n\nTranscript:\n${formattedTranscript}` },
  ]
  const requestCompletion = (useStructuredResponseFormat: boolean) =>
    getOpenAI().chat.completions.create({
      model: METADATA_MODEL,
      messages,
      temperature: 0.3,
      ...(useStructuredResponseFormat ? { response_format: { type: 'json_object' as const } } : {}),
    })

  const completion = await (async () => {
    try {
      return await requestCompletion(true)
    } catch (error: unknown) {
      if (!shouldRetryWithoutStructuredResponseFormat(error)) {
        throw error
      }

      return requestCompletion(false)
    }
  })()

  const content = completion.choices[0]?.message?.content
  if (!content) {
    throw new Error('No response from AI')
  }

  let parsedContent: unknown
  try {
    parsedContent = JSON.parse(content)
  } catch {
    throw new Error('AI returned invalid JSON. Please try again.')
  }

  const parsedNotes = generatedNotesSchema.safeParse(parsedContent)
  if (!parsedNotes.success) {
    throw new Error('AI returned invalid JSON. Please try again.')
  }

  return {
    title: parsedNotes.data.title?.trim() || 'Untitled Meeting',
    summary: parsedNotes.data.summary?.trim() || '',
    detailed_notes: parsedNotes.data.detailed_notes?.trim() || '',
    action_items: normalizeActionItems(parsedNotes.data.action_items),
    key_decisions: normalizeStringArray(parsedNotes.data.key_decisions),
    topics: normalizeStringArray(parsedNotes.data.topics),
    follow_ups: normalizeStringArray(parsedNotes.data.follow_ups),
  }
}

import * as Sentry from '@sentry/nextjs'
import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { errorResponse } from '@/lib/api/api-helpers'
import { validateBody } from '@/lib/api/validate'
import { generateNotesFromTranscript } from '@/lib/notes/notes-generation'
import { generatedNotesToTiptap } from '@/lib/tiptap/tiptap-converter'
import { createRateLimiter, checkRateLimit } from '@/lib/api/rate-limit'
import { translateToUserError } from '@/lib/notes/error-messages'
import { z } from 'zod'
import type { DiarizedSegment } from '@/lib/types'

const ratelimit = createRateLimiter(5, '1 m')

export const maxDuration = 60

const generateNotesRequestSchema = z.object({
  meetingId: z.string().trim().min(1),
  transcript: z.string().max(500_000).optional(),
})

export async function POST(request: NextRequest) {
  const supabase = await createClient()
  let meetingId: string | null = null
  let userId: string | null = null

  try {
    // Auth check
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
      return errorResponse('Unauthorized', 'UNAUTHORIZED', 401)
    }
    userId = user.id

    const allowed = await checkRateLimit(ratelimit, `generate_notes_${user.id}`, 'generate-notes')
    if (!allowed) {
      return errorResponse('Too Many Requests', 'RATE_LIMITED', 429)
    }

    const validated = await validateBody(request, generateNotesRequestSchema)
    if (validated instanceof Response) return validated
    meetingId = validated.data.meetingId
    const requestTranscript = validated.data.transcript

    // Verify user owns the meeting
    const { data: meeting } = await supabase
      .from('meetings')
      .select('id, user_id, transcript, template_id, diarized_transcript, audio_duration')
      .eq('id', meetingId)
      .eq('user_id', user.id)
      .single()

    if (!meeting) {
      return errorResponse('Meeting not found', 'MEETING_NOT_FOUND', 404)
    }

    const transcriptFromDb = typeof meeting.transcript === 'string' ? meeting.transcript : null
    const transcriptToProcess = transcriptFromDb || requestTranscript

    if (!transcriptToProcess || transcriptToProcess.trim().length === 0) {
      return errorResponse('Missing transcript', 'MISSING_TRANSCRIPT', 400)
    }

    // Update status
    await supabase
      .from('meetings')
      .update({ status: 'generating' })
      .eq('id', meetingId)
      .eq('user_id', user.id)

    const normalizedNotes = await generateNotesFromTranscript(supabase, {
      transcript: transcriptToProcess,
      templateId: meeting.template_id,
      userId: user.id,
      diarizedTranscript: meeting.diarized_transcript as DiarizedSegment[] | null,
      audioDuration: meeting.audio_duration as number | null,
    })

    // Save notes to database (including Tiptap document for the editor)
    const tiptapDocument = generatedNotesToTiptap(normalizedNotes)

    await supabase
      .from('meetings')
      .update({
        ...normalizedNotes,
        document_content: tiptapDocument,
        status: 'done',
        error_message: null,
        updated_at: new Date().toISOString(),
      })
      .eq('id', meetingId)
      .eq('user_id', user.id)

    return NextResponse.json({ notes: normalizedNotes, meetingId })
  } catch (error: unknown) {
    const translated = translateToUserError(error)

    // Set meeting status to error so it doesn't stay stuck
    if (meetingId && userId) {
      try {
        await supabase
          .from('meetings')
          .update({
            status: 'error',
            error_message: translated.userMessage,
            updated_at: new Date().toISOString(),
          })
          .eq('id', meetingId)
          .eq('user_id', userId)
      } catch (dbError) {
        Sentry.captureException(dbError)
      }
    }

    Sentry.captureException(error, {
      tags: { route: 'generate-notes' },
      extra: { developerMessage: translated.developerMessage },
    })
    return errorResponse(translated.userMessage, 'NOTES_GENERATION_FAILED', 500)
  }
}

'use client'

import { useState, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { Upload, X, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'
import type { MeetingStatus } from '@/lib/types'
import { uploadAndProcessMeeting } from '@/lib/meetings/meeting-upload'

const ACCEPTED_TYPES = ['audio/mpeg', 'audio/wav', 'audio/mp4', 'audio/x-m4a', 'audio/webm', 'audio/ogg']
const MAX_SIZE = 25 * 1024 * 1024 // 25MB (Whisper limit)

interface Props {
  onProcessing: (state: {
    meetingId: string
    step: MeetingStatus
    error?: string
  }) => void
  templateId?: string
}

export function AudioUploader({ onProcessing, templateId }: Props) {
  const router = useRouter()
  const fileInputRef = useRef<HTMLInputElement>(null)
  const [file, setFile] = useState<File | null>(null)
  const [isDragging, setIsDragging] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const submittingRef = useRef(false)

  const validateFile = (f: File): string | null => {
    if (!ACCEPTED_TYPES.includes(f.type) && !f.name.match(/\.(mp3|wav|m4a|webm|ogg)$/i)) {
      return 'Unsupported audio format. We accept common audio files like MP3 or WAV.'
    }
    if (f.size > MAX_SIZE) {
      return 'This file is too large. The maximum size is 25 MB.'
    }
    return null
  }

  const handleFile = (f: File) => {
    const error = validateFile(f)
    if (error) {
      toast.error(error)
      return
    }
    setFile(f)
  }

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)
    const f = e.dataTransfer.files[0]
    if (f) handleFile(f)
  }


  const handleSubmit = async () => {
    if (!file || submittingRef.current) return
    submittingRef.current = true
    setIsSubmitting(true)
    let currentMeetingId = ''

    try {
      const supabase = createClient()
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) throw new Error('Not authenticated')

      const { data: meeting, error: insertError } = await supabase
        .from('meetings')
        .insert({
          user_id: user.id,
          title: file.name.replace(/\.[^/.]+$/, ''),
          status: 'generating',
          ...(templateId ? { template_id: templateId } : {}),
        })
        .select('id')
        .single()

      if (insertError || !meeting) throw new Error('Failed to create meeting')
      currentMeetingId = meeting.id

      const extension = file.name.split('.').pop()?.toLowerCase() || 'webm'
      await uploadAndProcessMeeting({
        meetingId: meeting.id,
        userId: user.id,
        blob: file,
        extension,
        contentType: file.type || 'audio/webm',
        onProcessing,
      })
      router.push(`/dashboard/${meeting.id}`)
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Something went wrong'
      toast.error(message)
      onProcessing({ meetingId: currentMeetingId, step: 'error', error: message })
    } finally {
      submittingRef.current = false
      setIsSubmitting(false)
    }
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Drop zone */}
      <div
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true) }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={handleDrop}
        onClick={() => {
          if (!isSubmitting) fileInputRef.current?.click()
        }}
        role="button"
        tabIndex={isSubmitting ? -1 : 0}
        aria-disabled={isSubmitting}
        onKeyDown={(e) => {
          if (isSubmitting) return
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault()
            fileInputRef.current?.click()
          }
        }}
        className={`surface-utility flex cursor-pointer flex-col items-center justify-center gap-4 rounded-[24px] border-2 border-dashed px-6 py-16 transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${isDragging
          ? 'border-accent bg-accent/5'
          : 'border-border hover:border-muted-foreground/60'
          } ${isSubmitting ? 'pointer-events-none opacity-60' : ''}`}
        aria-label="Upload audio file"
      >
        <div className="surface-document flex size-12 items-center justify-center rounded-full">
          <Upload className="size-5 text-muted-foreground" />
        </div>
        <div className="flex flex-col items-center gap-1">
          <p className="text-sm font-medium text-foreground">
            Drop your audio file here
          </p>
          <p className="text-xs text-muted-foreground">
            MP3, WAV, M4A, WebM — up to 25 MB
          </p>
        </div>
        <input
          ref={fileInputRef}
          type="file"
          accept=".mp3,.wav,.m4a,.webm,.ogg,audio/*"
          onChange={(e) => {
            const f = e.target.files?.[0]
            if (f) handleFile(f)
          }}
          className="hidden"
          aria-label="Upload audio file"
        />
      </div>

      {/* Selected file */}
      {file && (
        <div className="surface-document flex items-center justify-between rounded-[22px] px-4 py-3">
          <div className="flex flex-col gap-0.5">
            <span className="text-sm font-medium text-foreground">{file.name}</span>
            <span className="text-xs text-muted-foreground">
              {(file.size / 1024 / 1024).toFixed(1)} MB
            </span>
          </div>
          <div className="flex items-center gap-3">
            <Button
              variant="ghost-icon"
              size="icon-sm"
              onClick={(e) => { e.stopPropagation(); setFile(null) }}
              aria-label="Remove file"
            >
              <X className="size-4" />
            </Button>
          </div>
        </div>
      )}

      {/* Submit */}
      {file && (
        <Button
          onClick={handleSubmit}
          disabled={isSubmitting}
          className="rounded-xl"
        >
          {isSubmitting ? (
            <>
              <Loader2 className="size-4 animate-spin" />
              Processing…
            </>
          ) : (
            'Generate notes'
          )}
        </Button>
      )}
    </div>
  )
}

